#include <stdio.h>
#include <stdlib.h>

int N;
int *leftChild, *rightChild, *ans;
int dfs(int u){
    if(u==0) return 0;
    int sz = 1 + dfs(leftChild[u]) + dfs(rightChild[u]);
    ans[u] = sz;
    return sz;
}
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        scanf("%d", &N);
        leftChild = (int*)calloc(N+1, sizeof(int));
        rightChild = (int*)calloc(N+1, sizeof(int));
        ans = (int*)calloc(N+1, sizeof(int));
        int root = 0;
        for(int i=1;i<=N;i++){
            int p; scanf("%d", &p);
            if(p==0) root = i;
            else if(p<0) leftChild[-p] = i;
            else rightChild[p] = i;
        }
        dfs(root);
        for(int i=1;i<=N;i++){
            if(i>1) printf(" ");
            printf("%d", ans[i]);
        }
        printf("\n");
        free(leftChild); free(rightChild); free(ans);
    }
    return 0;
}

