code.Python3:
import sys

def dfs(u, left, right, ans):
    if u == 0:
        return 0
    sz = 1 + dfs(left[u], left, right, ans) + dfs(right[u], left, right, ans)
    ans[u] = sz
    return sz

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        left = [0]*(N+1)
        right = [0]*(N+1)
        ans = [0]*(N+1)
        root = 0
        for i in range(1, N+1):
            p = int(next(it))
            if p == 0:
                root = i
            elif p < 0:
                left[-p] = i
            else:
                right[p] = i
        dfs(root, left, right, ans)
        out_lines.append(' '.join(str(ans[i]) for i in range(1, N+1)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

